import './ButtonSet.scss';

import { Button } from ':components/Button/Button';
import React from 'react';

import { classNames } from '../../helpers/classnames';
import type { ButtonSetProps } from './ButtonSet.types';

export const ButtonSet: React.FC<ButtonSetProps> = ({
	buttons,
	size = 'small',
	direction = 'horizontal',
	className,
	dataTestId = 'ButtonSet',
}) => {
	const rootClassName = classNames(
		'dsb_button-set',
		`dsb_button-set__${direction}`,
		`dsb_button-set__${size}`,
		className,
	);

	return (
		<div className={rootClassName} data-testid={dataTestId}>
			{buttons.map((button, index) => {
				const { id, ...buttonProps } = button;
				const key = id || `button-${index}`;

				return <Button key={key} {...buttonProps} size={size} fullWidth={direction === 'vertical'} />;
			})}
		</div>
	);
};
